#include<bits/stdc++.h>
using namespace std;
int n,q,a[101],siz[101],dp[101][101];
vector<pair<int,int>> mp[101];
void dfs(int x,int fa=-1)
{
    siz[x]=1;
    for(auto i:mp[x])
    {
        int v=i.first;
        if(v!=fa)
        {
            dp[v][1]=i.second;
            dfs(v,x);
            siz[x]+=siz[v];
            for(int j=siz[x];j>=1;j--)
            {
                for(int k=1;k<=siz[v]&&k<j;k++)
                {
                    dp[x][j]=max(dp[x][j],dp[x][j-k]+dp[v][k]);
                }
            }
        }
    }
}
int main()
{
    scanf("%d%d",&n,&q);
    for(int i=1;i<n;i++)
    {
        int u,v,w;
        scanf("%d%d%d",&u,&v,&w);
        mp[u].push_back(make_pair(v,w));
        mp[v].push_back(make_pair(u,w));
    }
    dfs(1);
    printf("%d",dp[1][q+1]);
    return 0;
}
